import sys
from bisect import bisect_left

input_data = sys.stdin.buffer.read().split()
idx = 0

def rd():
    global idx
    v = input_data[idx]; idx += 1
    return int(v)

t = rd()
for _ in range(t):
    m, n = rd(), rd()
    p = []
    for i in range(m):
        row = [rd() for _ in range(n)]
        p.append(row)

    # Collect all values, sort, binary search
    all_vals = sorted(set(v for row in p for v in row))

    def check(alpha):
        # Every friend coverable, and some shop covers 2+ friends
        friend_covered = [False] * n
        has_double = False
        for i in range(m):
            cnt = 0
            for j in range(n):
                if p[i][j] >= alpha:
                    friend_covered[j] = True
                    cnt += 1
            if cnt >= 2:
                has_double = True
        return all(friend_covered) and has_double

    lo, hi = 0, len(all_vals) - 1
    ans = 0
    while lo <= hi:
        mid = (lo + hi) // 2
        if check(all_vals[mid]):
            ans = all_vals[mid]
            lo = mid + 1
        else:
            hi = mid - 1

    print(ans)
